#include<bits/stdc++.h>
using namespace std;
vector<pair<long long,long long>> mp[250010],mp1[250010];
long long f[250010],ansmax,ansmin,anssum,a[250010],b[250010],min1[250010],max1[250010],dfn[250010],flag[250010],cnt[250010],g[250010],dfncnt,fa[250010][21],dis[250010],d[250010],lg[250010];
void dfs(long long x,long long f=0)
{
	dfn[x]=++dfncnt;
	fa[x][0]=f;
	d[x]=d[f]+1;
	for(long long i=1;i<=lg[d[x]];i++)
	{
		fa[x][i]=fa[fa[x][i-1]][i-1];
	}
	for(auto i:mp[x])
	{
		long long v=i.first,val=i.second;
		if(v!=f)
		{
			dis[v]=dis[x]+val;
			dfs(v,x);
		}
	}
}
long long lca(long long x,long long y)
{
	if(d[x]<d[y])
	{
		swap(x,y);
	}
	while(d[x]>d[y])
	{
		x=fa[x][lg[d[x]-d[y]]];
	}
	if(x==y)
	{
		return x;
	}
	for(long long i=lg[d[x]];i>=0;i--)
	{
		if(fa[x][i]!=fa[y][i])
		{
			x=fa[x][i];
			y=fa[y][i];
		}
	}
	return fa[x][0];
}
long long dist(long long x,long long y)
{
	return dis[x]+dis[y]-dis[lca(x,y)]*2;
}
bool cmp(long long x,long long y)
{
	return dfn[x]<dfn[y];
}
void dp(long long x,long long fa=-1)
{
	g[x]=0;
	cnt[x]=flag[x];
	if(!flag[x])
	{
		max1[x]=-1e18;
		min1[x]=1e18;
	}
	else
	{
		max1[x]=min1[x]=0;
	}
	for(auto i:mp1[x])
	{
		long long v=i.first,val=i.second;
		if(v!=fa)
		{
			dp(v,x);
			anssum+=(g[x]+cnt[x]*val)*cnt[v]+g[v]*cnt[x];
			g[x]+=g[v]+cnt[v]*val;
			cnt[x]+=cnt[v];
			ansmin=min(ansmin,min1[x]+min1[v]+val);
			ansmax=max(ansmax,max1[x]+max1[v]+val);
			min1[x]=min(min1[x],min1[v]+val);
			max1[x]=max(max1[x],max1[v]+val);
		}
	}
}
int main()
{
	long long n;
	scanf("%lld",&n);
	for(long long i=2;i<=n;i++)
	{
		lg[i]=lg[i/2]+1;
	}
	for(long long i=1;i<n;i++)
	{
		long long u,v;
		scanf("%lld%lld",&u,&v);
		mp[u].push_back({v,1});
		mp[v].push_back({u,1});
	}
	dfs(1);
	long long m;
	scanf("%lld",&m);
	while(m--)
	{
		long long k;
		scanf("%lld",&k);
		for(long long i=1;i<=k;i++)
		{
			scanf("%lld",&a[i]);
			flag[a[i]]=1;
		}
		ansmin=LLONG_MAX;
		ansmax=LLONG_MIN;
		anssum=0;
		sort(a+1,a+1+k,cmp);
		long long tot=0;
		for(long long i=1;i<k;i++)
		{
			b[++tot]=a[i];
			b[++tot]=lca(a[i],a[i+1]);
		}
		b[++tot]=a[k];
		b[++tot]=1;
		sort(b+1,b+1+tot);
		tot=unique(b+1,b+1+tot)-b-1;
		sort(b+1,b+1+tot,cmp);
		for(long long i=1;i<tot;i++)
		{
			long long l=lca(b[i],b[i+1]);
			mp1[l].push_back({b[i+1],dist(l,b[i+1])});
			mp1[b[i+1]].push_back({l,dist(l,b[i+1])});
		}
		dp(1);
		printf("%lld %lld %lld\n",anssum,ansmin,ansmax);
		for(long long i=1;i<=k;i++)
		{
			flag[a[i]]=0;
		}
		for(long long i=1;i<tot;i++)
		{
			long long l=lca(b[i],b[i+1]);
			mp1[l].clear();
			mp1[b[i+1]].clear();
		}
		for(long long i=1;i<=tot;i++)
		{
			f[i]=g[i]=cnt[i]=0;
		}
	}
	return 0;
}
